#!/usr/bin/env python3
"""Test edge cases for the validate_key fix."""

import numpy as np
from dask.core import validate_key

def test_edge_cases():
    """Test various edge cases for validate_key."""
    print("Testing edge cases...")

    # Empty tuple should work
    try:
        validate_key(())
        print("✓ validate_key(()) - OK")
    except Exception as e:
        print(f"✗ validate_key(()) failed: {e}")

    # Single element tuple with valid element
    try:
        validate_key(("single",))
        print("✓ validate_key(('single',)) - OK")
    except Exception as e:
        print(f"✗ validate_key(('single',)) failed: {e}")

    # Tuple with first element invalid
    try:
        validate_key((np.int64(1), 2, 3))
        print("✗ validate_key((np.int64(1), 2, 3)) should have failed!")
    except TypeError as e:
        print(f"First element error: {e}")
        if "index 0" in str(e):
            print("✓ Correctly identifies first element")

    # Tuple with last element invalid
    try:
        validate_key((1, 2, np.int64(3)))
        print("✗ validate_key((1, 2, np.int64(3))) should have failed!")
    except TypeError as e:
        print(f"Last element error: {e}")
        if "index 2" in str(e):
            print("✓ Correctly identifies last element")

    # Nested invalid tuple - should catch the outer invalid tuple component
    try:
        validate_key((1, (2, np.int64(3))))
        print("✗ validate_key((1, (2, np.int64(3)))) should have failed!")
    except TypeError as e:
        print(f"Nested error: {e}")
        # The outer tuple (2, np.int64(3)) is actually valid according to iskey
        # because iskey checks recursively, and this should fail at the np.int64 level

    # Actually test that nested works correctly
    from dask.core import iskey
    nested_tuple = (2, np.int64(3))
    print(f"iskey((2, np.int64(3))): {iskey(nested_tuple)}")  # Should be False

    # So this should fail
    try:
        validate_key((1, (2, np.int64(3))))
        print("✗ validate_key((1, (2, np.int64(3)))) should have failed!")
    except TypeError as e:
        print(f"Nesting handled correctly: {e}")

    # Test various invalid non-tuple types still work
    invalid_types = [
        ([1, 2], "list"),
        ({1: 2}, "dict"),
        ({1, 2}, "set"),
        (None, "None"),
    ]

    for invalid_key, name in invalid_types:
        try:
            validate_key(invalid_key)
            print(f"✗ validate_key({name}) should have failed!")
        except TypeError as e:
            print(f"{name} error: {e}")
            if "Unexpected key type" in str(e) and name in str(type(invalid_key)):
                print(f"✓ {name} error correctly formatted")

if __name__ == "__main__":
    test_edge_cases()

